// Helper: get LOB-level summary for a delegate (used on home page grouped view)
export const getLobSummaryForDelegate = (delegate) => {
  const lobMap = {};
  delegate.products.forEach((p) => {
    if (!lobMap[p.lob]) lobMap[p.lob] = { lob: p.lob, products: [], delegationTypes: new Set(), delegationCount: 0 };
    lobMap[p.lob].products.push(p.name);
    p.delegations.forEach((d) => lobMap[p.lob].delegationTypes.add(d.delegationType));
    lobMap[p.lob].delegationCount += p.delegations.length;
  });
  return Object.values(lobMap).map((l) => ({ ...l, delegationTypes: [...l.delegationTypes] }));
};

// Helper: flatten all delegations across all products for a delegate
export const getDelegationsForDelegate = (delegate) => {
  return delegate.products.flatMap((p) =>
    p.delegations.map((del) => ({ ...del, productName: p.name, productId: p.id, lob: p.lob }))
  );
};

// Helper: get all unique delegation types for a delegate
export const getDelegationTypes = (delegate) => {
  const types = new Set();
  delegate.products.forEach((p) =>
    p.delegations.forEach((d) => types.add(d.delegationType))
  );
  return [...types].sort().join(', ');
};

// Helper: get all unique product names for a delegate
export const getProducts = (delegate) => {
  return delegate.products.map((p) => p.name);
};

// Helper: get earliest upcoming audit date across all delegations
export const getNextAuditDue = (delegate) => {
  const dates = [];
  delegate.products.forEach((p) =>
    p.delegations.forEach((d) => {
      if (d.nextAuditDue) dates.push(d.nextAuditDue);
    })
  );
  dates.sort();
  return dates[0] || null;
};

// Helper: check if any delegation has an active CAP
export const hasActiveCAP = (delegate) => {
  return delegate.products.some((p) =>
    p.delegations.some((d) => d.correctiveActionPlan)
  );
};

// Helper: flat list of all delegations across all delegates (for ungrouped view & stats)
export const getAllDelegations = () => {
  return delegates.flatMap((d) =>
    d.products.flatMap((p) =>
      p.delegations.map((del) => ({
        ...del,
        delegateId: d.id,
        contractedEntity: d.contractedEntity,
        productName: p.name,
        productId: p.id,
        lob: p.lob,
      }))
    )
  );
};

// Helper: dashboard statistics
export const getStats = () => {
  const allDelegations = getAllDelegations();
  const today = new Date().toISOString().split('T')[0];

  return {
    totalDelegates: delegates.length,
    activeDelegations: allDelegations.filter((d) => d.status === 'Approved').length,
    overdueAudits: allDelegations.filter(
      (d) => d.nextAuditDue && d.nextAuditDue < today && d.status === 'Approved'
    ).length,
    openCAPs: allDelegations.filter((d) => d.correctiveActionPlan && d.status === 'Approved').length,
  };
};

export default delegates;
